import collections

class FenwickTree:
    def __init__(self, size):
        self.tree = [0] * (size + 1)
        self.size = size

    def update(self, index, delta):
        while index <= self.size:
            self.tree[index] += delta
            index += index & (-index)

    def query(self, index):
        s = 0
        while index > 0:
            s += self.tree[index]
            index -= index & (-index)
        return s

def countSmaller(nums):
    if not nums:
        return []

    sorted_unique_nums = sorted(list(set(nums)))
    val_to_rank = {val: i + 1 for i, val in enumerate(sorted_unique_nums)}

    ft_size = len(sorted_unique_nums)
    ft = FenwickTree(ft_size)

    result = [0] * len(nums)

    for i in range(len(nums) - 1, -1, -1):
        num = nums[i]
        rank = val_to_rank[num]

        smaller_count = ft.query(rank - 1)
        result[i] = smaller_count

        ft.update(rank, 1)

    return result
